SELECT reg.region_name, pt.annual_growth_rate_1990_2020 AS average_growth_rate
FROM population_trends pt
JOIN regions reg ON reg.region_id = pt.region_id;

SELECT r.region_name, p.year_2020
FROM regions r
JOIN population_data p ON r.region_id = p.region_id
WHERE r.population_density_2020 > (
    SELECT AVG(population_density_2020) FROM regions
);

SELECT r.region_name
FROM regions r
WHERE r.population_density_2020 > (SELECT AVG(population_density_2020) FROM regions);
